class Solution:
    def maxSum(self, nums):
        def largest_digit(v):
            best = 0
            while v > 0:
                best = max(best, v % 10)
                v //= 10
            return best
        n = len(nums)
        best = -1
        for i in range(n):
            for j in range(i + 1, n):
                if largest_digit(nums[i]) == largest_digit(nums[j]):
                    best = max(best, nums[i] + nums[j])
        return best

