class Solution:
    def maxSum(self, nums):
        def largest_digit(v):
            best = 0
            while v > 0:
                best = max(best, v % 10)
                v //= 10
            return best
        top = {}
        ans = -1
        for v in nums:
            key = largest_digit(v)
            if key not in top:
                top[key] = [v]
            else:
                top[key].append(v)
                top[key].sort(reverse=True)
                top[key] = top[key][:2]
        for vals in top.values():
            if len(vals) == 2:
                ans = max(ans, vals[0] + vals[1])
        return ans

