var maxSum = function(nums) {
    function largestDigit(v) {
        let best = 0;
        while (v > 0) {
            best = Math.max(best, v % 10);
            v = Math.floor(v / 10);
        }
        return best;
    }
    const top = new Map();
    let ans = -1;
    for (const v of nums) {
        const key = largestDigit(v);
        if (!top.has(key)) {
            top.set(key, [v]);
        } else {
            const arr = top.get(key);
            arr.push(v);
            arr.sort((a, b) => b - a);
            top.set(key, arr.slice(0, 2));
        }
    }
    for (const vals of top.values()) {
        if (vals.length === 2) ans = Math.max(ans, vals[0] + vals[1]);
    }
    return ans;
};
